const caddieCount=document.getElementById("caddie-count");document.getElementById("shop-grid").addEventListener("click",async t=>{const e=t.target.closest(".product-card__cart");if(!e)return;t.preventDefault(),t.stopPropagation();const o=e.dataset.id;try{const t=await fetch("../back/router.php?action=add-caddie",{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/json","X-CSRF-TOKEN":getCsrfToken()},body:JSON.stringify({productId:o,quantity:1})}),e=await t.json();e.success?(showNotification("Produit ajouté au panier","green"),caddieCount.textContent=e.count):showNotification(e.message,"red")}catch(t){console.error(t)}});